161→export default async function createSimpleDeepAgent(
162→  model: BaseLanguageModel,
163→  conversationId: string,
164→  sandboxManager: ConversationSandboxManager,
165→): Promise<ReturnType<typeof createDeepAgent>> {
166→  const session = await sandboxManager.getConversationSandbox(conversationId);
167→  const client = new MultiServerMCPClient({
168→    grafana: {
169→      transport: 'sse',
170→      url: configSchema.GRAFANA_MCP_URL!,
171→    },
172→  });
173→
174→  // 过滤，只剩下
175→  const FILTER_TOOLS = ['search_dashboards', 'list_datasources', 'get_dashboard_panel_queries', 'query_prometheus', 'list_prometheus_label_names', 'generate_deeplink', 'get_dashboard_by_uid'];
176→  const allMcpTools = (await client.getTools()).filter(tool => FILTER_TOOLS.includes(tool.name)) as DynamicStructuredTool[]
177→
178→  return createDeepAgent({
179→    model: model,
180→    tools: allMcpTools,
181→    sharedMiddleware: [
182→      contextOverflowBridgeMiddleware,
183→      vfsRelativePathMiddleware,
184→      createToolErrorMiddleware(),
185→      createStrictToolEvictionMiddleware(session.backend),
186→    ],
187→    backend: session.backend,
188→    checkpointer: memory,
189→    skills: [SANDBOX_SKILLS_ROOT]
190→  });
191→}
