  8→export type SandboxInitialFiles = Record<string, string | Uint8Array>;
  9→
 10→export interface SandboxInitialFilesProvider {
 11→  getInitialFiles(): Promise<SandboxInitialFiles>;
 12→}
 13→
 14→interface LocalSkillsSandboxInitialFilesProviderOptions {
 15→  skillsRoot?: string;
 16→}
 17→
 18→interface ListLocalSkillNamesOptions {
 19→  skillsRoot?: string;
 20→}
