348→  private async pipe(
349→    id: string,
350→    generator: AsyncGenerator<IGraphEvent>,
351→    response: PassThrough,
352→    ac: AbortController,
353→    save: (chunk?: ILinkedEvent) => Promise<void>,
354→  ) {
355→    const aggregate = this.createChunkAggregator();
356→    const send = async (chunk: ILinkedEvent) => {
357→      const tokenUsage = this.extractTokenUsageFromAssistantEnd(chunk);
358→      if (tokenUsage) {
359→        await this.conversationModel.updateOne({ id }, { tokenUsage });
360→      }
361→
362→      // 这里在保存的时候，会因为aggregate的累加机制，使得id不变，但是内容不断累加
363→      await save(aggregate(chunk as IGraphEvent));
364→
365→      if (!response.destroyed) {
366→        const payload = this.toClientEvent(chunk as unknown as Record<string, unknown>);
367→        return new Promise<void>((resolve, reject) =>
368→          response.write(`${JSON.stringify(payload)}\n`, error => {
369→            if (error) {
370→              reject(error);
371→            } else {
372→              resolve();
373→            }
374→          }),
375→        );
376→      }
377→    };
378→
379→    const writeKeepAlive = () => {
380→      if (!response.destroyed) {
381→        response.write('\n');
382→      }
383→    };
384→
385→    try {
386→      await this.conversation.start(id);
387→
388→      const keepAliveInterval = setInterval(writeKeepAlive, 15_000);
389→      try {
390→        for await (const chunk of generator) {
391→          await this.checkAborted(id, ac);
392→          await send(chunk);
393→        }
394→      } finally {
395→        clearInterval(keepAliveInterval);
396→      }
397→      await send({ id: randomUUID(), event: 'end', timestamp: Date.now() });
398→    } catch (error) {
399→      const message = formatError(error);
400→      const causeChain = getErrorCauseChain(error);
401→      this.logger.error({
402→        conversationId: id,
403→        message,
404→        causeChain,
405→        rootCause: causeChain[causeChain.length - 1],
406→        aborted: ac.signal.aborted,
407→      }, 'Chat stream failed');
408→      await send({ id: randomUUID(), event: 'error', data: message, timestamp: Date.now() });
409→    } finally {
410→      save();
411→      response.end();
412→      await this.conversation.stop(id);
413→    }
414→  }
415→
416→  private async checkAborted(id: string, ac: AbortController) {
417→    const generating = await this.conversation.isGenerating(id);
418→    if (generating) {
419→      await this.conversation.chunk(id);
420→    } else {
421→      ac.abort();
422→      // compatible with abort error message of langgraph
423→      throw new Error('Aborted');
424→    }
425→  }
426→
427→  private enableStream(request: Request, response: Response) {
428→    request.socket.setTimeout(0);
429→    request.socket.setNoDelay();
430→    request.socket.setKeepAlive(true);
431→    response.setHeader('content-type', 'text/plain; charset=utf-8');
432→    response.setHeader('cache-control', 'no-cache');
433→    response.setHeader('connection', 'keep-alive');
434→  }
435→}
