71→export function retry<T>(action: () => Promise<T>, { interval, max = 32 }: IRetryOptions = {}) {
72→  let count = 0;
73→
74→  return function wrap(): Promise<T> {
75→    return action().catch(error => {
76→      if (count === max) {
77→        throw error;
78→      }
79→
80→      count++;
81→      if (interval) {
82→        return new Promise(resolve => setTimeout(resolve, interval)).then(wrap);
83→      } else {
84→        return wrap();
85→      }
86→    });
87→  };
88→}
